   failingChecks: 5,
   pendingChecks: 3,
   failingStatuses: 5,
   pendingStatuses: 3,
   scanningAlerts: 5,
 } as const;

 export const CHAT_SIGNAL_CAPS = {
   failingChecks: 3,
   pendingChecks: 2,
