// GitHub Types
export interface GitHubUser {
  login: string;
  avatar_url: string;
  html_url: string;
}

export interface GitHubRepository {
  id: number;
  name: string;
  full_name: string;
  description: string | null;
  private: boolean;
  html_url: string;
  owner: GitHubUser;
  default_branch: string;
}

export interface PullRequest {
  id: number;

import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit';
import { createGitHubService } from '../../services/github';
import { createLLMService } from '../../services/llm';
import { runEffect } from '../../effect/runtime';
import { loadPullRequestContext } from '../../effect/loadPullRequestContext';
import { toRejectedErrorData } from '../../effect/errors';
import {
  buildSummaryCacheKey,
  buildSummaryRateLimitKey,
  canGenerateSummary,
  hasTextualDiffContent,
  markSummaryGenerated,
  readSummaryCache,
  writeSummaryCache,
} from '../../services/summary';
import type {
  PullRequest,
  PRListItem,
  PRFile,
  PRComment,

import type {
  LLMMessage,
  LLMChatRequest,
  LLMChatResponse,
  LLMStreamChunk,
  PRContext,
  PRCommit,
  AppConfig,
} from '../types';

export class LLMService {
  private static readonly MAX_SYSTEM_PROMPT_CHARS = 24_000;

  private config: AppConfig;

  constructor(config: AppConfig) {
    this.config = config;
