   const nav = resolveCitationForNavigation(citation, files);
   const displayText = citation.lineStart
     ? citation.lineEnd
       ? `${citation.file}#${citation.lineStart}-${citation.lineEnd}`
       : `${citation.file}#${citation.lineStart}`
